PRAGMA foreign_keys = off;
BEGIN TRANSACTION;

-- Table: InventoryItems
CREATE TABLE InventoryItems (UserId INTEGER, ChatId INTEGER, ItemId STRING, Count INTEGER DEFAULT (0), PRIMARY KEY (UserId, ChatId, ItemId));

-- Table: Items
CREATE TABLE Items (Id STRING PRIMARY KEY, Name STRING, Type STRING, Stars INTEGER, Description STRING, Image STRING);

-- Table: UsersInChats
CREATE TABLE UsersInChats (UserId STRING, ChatId STRING, HasRolled BOOLEAN DEFAULT (0), FourPity INTEGER DEFAULT (0), FivePity INTEGER DEFAULT (0), PRIMARY KEY (UserId, ChatId));

COMMIT TRANSACTION;
PRAGMA foreign_keys = on;
