INSERT INTO Items (Id, Name, Type, Stars, Description, Image) VALUES ('lostprayer', 'Lost Prayer to the Secret Winds', 'Weapon', 5, 'An educational tome written by anonymous early inhabitants who worshiped the wind. It has been blessed by the wind for its faithfulness and influence over the millennia.', 'AgACAgIAAxkBAAICDGAW-zPKeZy1nAbstpgkiIp9PpFIAALUszEbUc24SNaPnMoIkwx0N0sQmC4AAwEAAwIAA20AA-VgBgABHgQ');
INSERT INTO Items (Id, Name, Type, Stars, Description, Image) VALUES ('skyharp', 'Skyward Harp', 'Weapon', 5, 'A greatbow that symbolizes Dvalin''s affiliation with the Anemo Archon. The sound of the bow firing is music to the Anemo Archon''s ears. It contains the power of the sky and wind within.', 'AgACAgIAAxkBAAICDmAW-zhpx4hecz-Eo-SSpYuPexV7AALVszEbUc24SKOafWihtejYV1YRmy4AAwEAAwIAA20AA0csAQABHgQ');
INSERT INTO Items (Id, Name, Type, Stars, Description, Image) VALUES ('skypride', 'Skyward Pride', 'Weapon', 5, 'A claymore that symbolizes the pride of Dvalin soaring through the skies. When swung, it emits a deep hum as the full force of Dvalin''s command of the sky and the wind is unleashed.', 'AgACAgIAAxkBAAICEGAW-z5FcycN9tQsNu7pOrshcHTuAALWszEbUc24SKhEum6zFiQBFptxly4AAwEAAwIAA20AAyttBgABHgQ');
INSERT INTO Items (Id, Name, Type, Stars, Description, Image) VALUES ('amos', 'Amos'' Bow', 'Weapon', 5, 'An extremely ancient bow that has retained its power despite its original master being long gone. It draws power from everyone and everything in the world, and the further away you are from that which your heart desires the more.', 'AgACAgIAAxkBAAICEmAW-0Wo5v45DA9CIYCF4sbb7gluAALXszEbUc24SO_5iAMB1dqc6vhply4AAwEAAwIAA20AA-dwBgABHgQ');
